// 1. Extraer campos del payload Tally.so
// Estructura: { data: { fields: [{ label, value }], submittedAt } }
const fields = $json?.data?.fields ?? [];

function getField(label) {
  const f = fields.find(f => f.label?.toLowerCase() === label.toLowerCase());
  if (!f) return '';
  return Array.isArray(f.value) ? (f.value[0] ?? '') : String(f.value ?? '');
}

const submittedAt = $json?.data?.submittedAt ?? new Date().toISOString();

return [{
  json: {
    summary:         getField('Summary'),
    pros:            getField('Pros'),
    cons:            getField('Cons'),
    department:      getField('Department') || 'Engineering & Tech',
    seniority:       getField('Seniority')  || 'Senior',
    gender:          getField('Gender')     || 'Prefer not to say',
    submission_date: submittedAt.split('T')[0],
    _submitted_at:   submittedAt
  }
}];

// 2. Llamar a FastAPI /predict
const input = $json;

const body = {
  summary:         input.summary,
  pros:            input.pros,
  cons:            input.cons,
  department:      input.department,
  seniority:       input.seniority,
  gender:          input.gender,
  submission_date: input.submission_date
};

const resp = await fetch('http://localhost:8000/predict', {
  method:  'POST',
  headers: { 'Content-Type': 'application/json' },
  body:    JSON.stringify(body)
});

if (!resp.ok) {
  throw new Error(`FastAPI error ${resp.status}: ${await resp.text()}`);
}

const prediction = await resp.json();

// Pasar tanto el input original como la predicción
return [{ json: { ...prediction, _input: input } }];

// 3. Escribir fila en gold.csv
const fs = require('fs');

// Ajusta CSV_PATH a la ruta absoluta de Dashboard/gold.csv en tu máquina
const CSV_PATH = process.env.GOLD_CSV_PATH || './gold.csv';
const COLS = [
  'timestamp', 'summary', 'pros', 'cons',
  'department', 'seniority', 'gender',
  'predicted_rating', 'satisfaction', 'confidence'
];

const pred  = $json;
const input = pred._input ?? {};

const row = {
  timestamp:        new Date().toISOString(),
  summary:          input.summary          ?? '',
  pros:             input.pros             ?? '',
  cons:             input.cons             ?? '',
  department:       pred.department        ?? input.department ?? '',
  seniority:        pred.seniority         ?? input.seniority  ?? '',
  gender:           pred.gender            ?? input.gender     ?? '',
  predicted_rating: pred.predicted_rating  ?? '',
  satisfaction:     pred.satisfaction      ?? '',
  confidence:       pred.confidence        ?? ''
};

function escapeCSV(val) {
  const s = String(val ?? '');
  return (s.includes(',') || s.includes('"') || s.includes('\n'))
    ? '"' + s.replace(/"/g, '""') + '"'
    : s;
}

// Crear fichero con cabecera si no existe
if (!fs.existsSync(CSV_PATH)) {
  fs.writeFileSync(CSV_PATH, COLS.join(',') + '\n', 'utf8');
}

fs.appendFileSync(CSV_PATH, COLS.map(c => escapeCSV(row[c])).join(',') + '\n', 'utf8');

return [{ json: { status: 'ok', satisfaction: row.satisfaction, predicted_rating: row.predicted_rating } }];
